#include<bits/stdc++.h>
using namespace std;
long long n,m;
long long dis1[210],cost[210][210],dis2[210],flag[400010],dis1toi[210],disito1[210],disntoi[210],disiton[210],U[400010],V[400010],W[400010],D[400010];
long long pre1[210][2],pre2[210][2];
bool vis[210];
struct edge
{
    long long to,val,cost,id;
    edge(long long a=0,long long b=0,long long c=0,long long d=0):to(a),val(b),cost(c),id(d){}
};
vector<edge> mp[210],mp1[210];
void dijkstra()
{
    memset(dis1,0x3f,sizeof(dis1));
    memset(vis,0,sizeof(vis));
    dis1[1]=0;
    for(long long i=1;i<=n;i++)
    {
        long long min1=LLONG_MAX,min2=0;
        for(long long j=1;j<=n;j++)
        {
            if(!vis[j]&&dis1[j]<min1)
            {
                min1=dis1[j];
                min2=j;
            }
        }
        dis1toi[min2]=dis1[min2];
        vis[min2]=true;
        // printf("dijkstra#1 vis[%d]=true\n",min2);
        for(long long k=0;k<mp[min2].size();k++)
        {
            auto j=mp[min2][k];
            long long v=j.to,val=j.val;
            if(!vis[v]&&dis1[v]>dis1[min2]+val)
            {
                dis1[v]=dis1[min2]+val;
                pre1[v][0]=k;
                pre1[v][1]=min2;
            }
        }
    }
    // printf("dijkstra#1 end\n");
    memset(dis2,0x3f,sizeof(dis2));
    memset(vis,0,sizeof(vis));
    dis2[n]=0;
    for(long long i=1;i<=n;i++)
    {
        long long min1=LLONG_MAX,min2=0;
        for(long long j=1;j<=n;j++)
        {
            if(!vis[j]&&dis2[j]<min1)
            {
                min1=dis2[j];
                min2=j;
            }
        }
        disntoi[min2]=dis2[min2];
        vis[min2]=true;
        // printf("dijkstra#2 vis[%d]=true\n",min2);
        for(long long k=0;k<mp[min2].size();k++)
        {
            auto j=mp[min2][k];
            long long v=j.to,val=j.val;
            if(!vis[v]&&dis2[v]>dis2[min2]+val)
            {
                dis2[v]=dis2[min2]+val;
                pre2[v][0]=k;
                pre2[v][1]=min2;
            }
        }
    }
}
