int main()
{
    memset(pre1,-1,sizeof(pre1));
    memset(pre2,-1,sizeof(pre2));
    scanf("%lld%lld",&n,&m);
    for(long long i=1;i<=m;i++)
    {
        long long u,v,c,d;
        scanf("%lld%lld%lld%lld",&u,&v,&c,&d);
        U[i]=u,V[i]=v,W[i]=c,D[i]=d;
        // printf("push back start\n");
        // printf("u=%lld v=%lld c=%lld d=%lld\n",u,v,c,d);
        mp[u].push_back(edge(v,c,d,i));
        mp1[v].push_back(edge(u,c,d,i));
        // printf("push back end\n");
    }
    // printf("dijkstra start\n");
    dijkstra();
    dijkstra0();
    // printf("dijkstra finish\n");
    long long ans=dis1[n]+dis2[1];
    for(long long i=1;i<=n;i++)
    {
        if(pre1[i][0]!=-1)
        {
            long long p=pre1[i][0];
            long long from=pre1[i][1];
            auto tmp=mp[from][p];
            flag[tmp.id]=1;
            if(p+1!=mp[from].size())
            {
                swap(mp[from][p],mp[from][mp[from].size()-1]);
            }
            mp[from].pop_back();
            mp[i].push_back(edge(from,tmp.val,tmp.cost,tmp.id));
            dijkstra1();
            mp[i].pop_back();
            mp[from].push_back(tmp);
            if(p+1!=mp[from].size())
            {
                swap(mp[from][p],mp[from][mp[from].size()-1]);
            }
            ans=min(ans,dis1[n]+dis2[1]+tmp.cost);
        }
        if(pre2[i][0]!=-1)
        {
            long long p=pre2[i][0];
            long long from=pre2[i][1];
            auto tmp=mp[from][p];
            flag[tmp.id]=1;
            if(p+1!=mp[from].size())
            {
                swap(mp[from][p],mp[from][mp[from].size()-1]);
            }
            mp[from].pop_back();
            mp[i].push_back(edge(from,tmp.val,tmp.cost,tmp.id));
            dijkstra1();
            mp[i].pop_back();
            mp[from].push_back(tmp);
            if(p+1!=mp[from].size())
            {
                swap(mp[from][p],mp[from][mp[from].size()-1]);
            }
            ans=min(ans,dis1[n]+dis2[1]+tmp.cost);
        }
    }
    for(long long i=1;i<=m;i++)if(!flag[i])
    {
        long long u=U[i],v=V[i],w=W[i],d=D[i];
        ans=min(ans,d+min(dis1toi[n],dis1toi[v]+w+disiton[u])+min(disntoi[1],disntoi[v]+w+disito1[u]));
    }
    if(ans>1e18)
    {
        ans=-1;
    }
    printf("%lld\n",ans);
    return 0;
}
